import sys

def solve():
    import sys
    input = sys.stdin.read
    data = input().split()
    N = int(data[0])
    P = list(map(int, data[1:]))

    ranks = [0] * N
    used = [False] * N
    r = 1

    while True:
        max_score = -1
        candidates = []
        for i in range(N):
            if not used[i] and P[i] > max_score:
                max_score = P[i]
                candidates = [i]
            elif not used[i] and P[i] == max_score:
                candidates.append(i)
        if not candidates:
            break
        for idx in candidates:
            ranks[idx] = r
        r += len(candidates)
        for idx in candidates:
            used[idx] = True

    for rank in ranks:
        print(rank)

if __name__ == "__main__":
    solve()
